import (
	"bufio"
	"fmt"
	"os"
	"strconv"
	"strings"
)

// maximumDetonation encontra a maior reação em cadeia possível
func maximumDetonation(bombs [][]int) int {
	n := len(bombs)

	// Cria uma lista de adjacência para o nosso Grafo Direcionado
	adj := make([][]int, n)

	// Monta o Grafo testando todas as combinações de bombas
	for i := 0; i < n; i++ {
		for j := 0; j < n; j++ {
			if i == j {
				continue // Uma bomba não precisa detonar a si mesma
			}

			// Converte para int64 para evitar overflow na multiplicação
			dx := int64(bombs[i][0] - bombs[j][0])
			dy := int64(bombs[i][1] - bombs[j][1])
			r := int64(bombs[i][2])

			// Se a bomba J estiver dentro da área da bomba I, cria uma conexão
			if dx*dx + dy*dy <= r*r {
				adj[i] = append(adj[i], j)
			}
		}
	}

	maxDetonated := 0

	// Testa detonar cada uma das bombas individualmente
	for i := 0; i < n; i++ {
		visited := make([]bool, n)

		// Inicia a DFS (Busca em Profundidade) a partir da bomba 'i'
		count := dfs(i, adj, visited)

		// Atualiza o recorde
		if count > maxDetonated {
			maxDetonated = count
		}
	}

	return maxDetonated
}

// dfs percorre o grafo e conta quantas bombas foram alcançadas
func dfs(u int, adj [][]int, visited []bool) int {
	visited[u] = true
	count := 1 // Conta a bomba atual

	// Visita as bombas que esta bomba consegue detonar
	for _, v := range adj[u] {
		if !visited[v] {
			count += dfs(v, adj, visited)
		}
	}

	return count
}

// --- Leitura Padrão TKO ---

scanner := bufio.NewScanner(os.Stdin)
if !scanner.Scan() {
	return
}
parts := strings.Fields(scanner.Text())
if len(parts) < 2 {
	return
}

nl, _ := strconv.Atoi(parts[0]) 

bombs := make([][]int, nl)
for i := 0; i < nl; i++ {
	if !scanner.Scan() {
		return
	}
	tokens := strings.Fields(scanner.Text())
	bomb := make([]int, 3)
	for j := 0; j < 3 && j < len(tokens); j++ {
		bomb[j], _ = strconv.Atoi(tokens[j])
	}
	bombs[i] = bomb
}

fmt.Println(maximumDetonation(bombs))
